import 'package:flutter/material.dart';
import 'package:flutter_svg/flutter_svg.dart';
import '../services/gemini_service.dart';
import '../widgets/review_summary_card.dart';
import 'start_screen.dart';

/// Shows final score, a celebration asset, and the Smart Review Summary
/// (Advanced Feature 1) generated by Gemini 2.5 Flash.
class ResultScreen extends StatefulWidget {
  final int score;
  final int totalQuestions;
  final int missed;
  final Map<String, int> missedCategories;
  final Map<String, int> missedDifficulties;

  const ResultScreen({
    super.key,
    required this.score,
    required this.totalQuestions,
    required this.missed,
    required this.missedCategories,
    required this.missedDifficulties,
  });

  @override
  State<ResultScreen> createState() => _ResultScreenState();
}

class _ResultScreenState extends State<ResultScreen> {
  bool _isGeneratingSummary = true;
  String _summaryText = '';

  @override
  void initState() {
    super.initState();
    _loadSummary();
  }

  // ─── Smart Review Summary ─────────────────────────────────────────────────

  Future<void> _loadSummary() async {
    setState(() => _isGeneratingSummary = true);

    final summary = await GeminiService.generateReviewSummary({
      'score': widget.score,
      'total': widget.totalQuestions,
      'missed': widget.missed,
      'missedCategories': widget.missedCategories,
      'missedDifficulties': widget.missedDifficulties,
    });

    if (mounted) {
      setState(() {
        _isGeneratingSummary = false;
        _summaryText = summary;
      });
    }
  }

  void _playAgain() {
    Navigator.pushAndRemoveUntil(
      context,
      MaterialPageRoute(builder: (_) => const StartScreen()),
      (_) => false,
    );
  }

  // ─── Build ─────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);
    final pct = widget.totalQuestions > 0
        ? ((widget.score / widget.totalQuestions) * 100).round()
        : 0;

    return Scaffold(
      backgroundColor: const Color(0xFFF5F8FF),
      appBar: AppBar(
        backgroundColor: const Color(0xFF1A237E),
        foregroundColor: Colors.white,
        title: const Text('Quiz Complete'),
        automaticallyImplyLeading: false,
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.symmetric(horizontal: 24, vertical: 28),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            // celebration.svg: rewards the student, signals quiz is done,
            // and motivates replay — purposeful use of asset for UX.
            SvgPicture.asset(
              'assets/images/celebration.svg',
              width: 160,
              height: 160,
            ),
            const SizedBox(height: 16),

            // Score display
            Text(
              '$pct%',
              style: theme.textTheme.displaySmall?.copyWith(
                fontWeight: FontWeight.bold,
                color: _scoreColor(pct),
              ),
              textAlign: TextAlign.center,
            ),
            Text(
              '${widget.score} / ${widget.totalQuestions} correct',
              style: theme.textTheme.titleMedium?.copyWith(
                color: Colors.black54,
              ),
              textAlign: TextAlign.center,
            ),
            const SizedBox(height: 6),
            Text(
              _scoreLabel(pct),
              style: theme.textTheme.bodyMedium?.copyWith(
                color: Colors.black54,
                fontStyle: FontStyle.italic,
              ),
              textAlign: TextAlign.center,
            ),
            const SizedBox(height: 28),

            // Smart Review Summary card (Feature 1)
            ReviewSummaryCard(
              isLoading: _isGeneratingSummary,
              summaryText: _summaryText,
            ),
            const SizedBox(height: 28),

            // Play Again button
            SizedBox(
              height: 52,
              child: ElevatedButton.icon(
                onPressed: _playAgain,
                icon: const Icon(Icons.replay_rounded),
                label: const Text(
                  'Play Again',
                  style: TextStyle(fontSize: 16, fontWeight: FontWeight.w700),
                ),
                style: ElevatedButton.styleFrom(
                  backgroundColor: const Color(0xFF4A90D9),
                  foregroundColor: Colors.white,
                  shape: RoundedRectangleBorder(
                      borderRadius: BorderRadius.circular(14)),
                  elevation: 3,
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  Color _scoreColor(int pct) {
    if (pct >= 80) return const Color(0xFF2E7D32);
    if (pct >= 60) return const Color(0xFFF57C00);
    return const Color(0xFFC62828);
  }

  String _scoreLabel(int pct) {
    if (pct == 100) return 'Perfect score!';
    if (pct >= 80) return 'Great job!';
    if (pct >= 60) return 'Good effort!';
    if (pct >= 40) return 'Keep practicing!';
    return 'Don\'t give up — every quiz teaches you something.';
  }
}
